def solution(n: int = 1001) -> int:
    if n == 1: return 1
    total = 1
    current = 1
    # side_len goes 3, 5, 7 ... n
    for side_len in range(3, n + 1, 2):
        gap = side_len - 1
        for _ in range(4):
            current += gap
            total += current
    return total


if __name__ == "__main__":
    print(solution(1001))
